/**
 * Analytics service — aggregates data from users and orders
 * to produce dashboard metrics.
 *
 * Depends on:
 * - OrderRepository (data layer) for order data
 * - UserRepository (data layer) for user data
 */

import type { AnalyticsSummary, UserAnalytics, TrendPoint } from '../models/analytics.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get a high-level summary of platform metrics.
   */
  getSummary(): AnalyticsSummary {
    this.logger.info('Generating analytics summary');

    const users = this.userRepository.findAll();
    const orders = this.orderRepository.findAll();

    const revenue = orders
      .filter((o) => o.status !== 'cancelled')
      .reduce((sum, o) => sum + o.total, 0);

    const userIdsWithOrders = new Set(orders.map((o) => o.userId));
    const activeUsers = userIdsWithOrders.size;

    return {
      totalUsers: users.length,
      totalOrders: orders.length,
      revenue,
      activeUsers,
    };
  }

  /**
   * Get analytics for a specific user.
   */
  getUserAnalytics(userId: string): UserAnalytics {
    this.logger.info(`Generating analytics for user: ${userId}`);

    const user = this.userRepository.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const orders = this.orderRepository.findByUserId(userId);

    const totalSpent = orders
      .filter((o) => o.status !== 'cancelled')
      .reduce((sum, o) => sum + o.total, 0);

    const lastActive = orders.length > 0
      ? orders.reduce((latest, o) =>
          o.updatedAt > latest ? o.updatedAt : latest, orders[0]!.updatedAt)
      : user.createdAt;

    return {
      userId,
      orderCount: orders.length,
      totalSpent,
      lastActive,
    };
  }

  /**
   * Get trend data points for orders over time.
   * Groups orders by date and returns daily order count and revenue trends.
   */
  getTrends(): TrendPoint[] {
    this.logger.info('Generating trend data');

    const orders = this.orderRepository.findAll();
    const dailyData = new Map<string, { count: number; revenue: number }>();

    for (const order of orders) {
      const dateKey = order.createdAt.toISOString().split('T')[0]!;
      const existing = dailyData.get(dateKey) ?? { count: 0, revenue: 0 };
      existing.count += 1;
      if (order.status !== 'cancelled') {
        existing.revenue += order.total;
      }
      dailyData.set(dateKey, existing);
    }

    const trends: TrendPoint[] = [];
    const sortedDates = [...dailyData.keys()].sort();

    for (const date of sortedDates) {
      const data = dailyData.get(date)!;
      const timestamp = new Date(date);
      trends.push({ timestamp, metric: 'orders', value: data.count });
      trends.push({ timestamp, metric: 'revenue', value: data.revenue });
    }

    return trends;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

describe('AnalyticsService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let service: AnalyticsService;

  const now = new Date('2025-06-15T12:00:00Z');
  const yesterday = new Date('2025-06-14T10:00:00Z');

  function createUser(id: string, name: string): User {
    const user: User = {
      id,
      name,
      email: `${name.toLowerCase()}@example.com`,
      role: 'member',
      createdAt: now,
      updatedAt: now,
    };
    userRepo.save(user);
    return user;
  }

  function createOrder(
    id: string,
    userId: string,
    total: number,
    status: Order['status'] = 'confirmed',
    createdAt: Date = now,
  ): Order {
    const order: Order = {
      id,
      userId,
      items: [{ productId: 'p1', name: 'Item', quantity: 1, unitPrice: total }],
      total,
      status,
      createdAt,
      updatedAt: createdAt,
    };
    orderRepo.save(order);
    return order;
  }

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  describe('getSummary', () => {
    it('should return zeros when there are no users or orders', () => {
      const summary = service.getSummary();
      expect(summary.totalUsers).toBe(0);
      expect(summary.totalOrders).toBe(0);
      expect(summary.revenue).toBe(0);
      expect(summary.activeUsers).toBe(0);
    });

    it('should count users and orders', () => {
      createUser('u1', 'Alice');
      createUser('u2', 'Bob');
      createOrder('o1', 'u1', 50);
      createOrder('o2', 'u1', 30);
      createOrder('o3', 'u2', 20);

      const summary = service.getSummary();
      expect(summary.totalUsers).toBe(2);
      expect(summary.totalOrders).toBe(3);
      expect(summary.activeUsers).toBe(2);
    });

    it('should exclude cancelled orders from revenue', () => {
      createUser('u1', 'Alice');
      createOrder('o1', 'u1', 100, 'confirmed');
      createOrder('o2', 'u1', 50, 'cancelled');

      const summary = service.getSummary();
      expect(summary.revenue).toBe(100);
      expect(summary.totalOrders).toBe(2);
    });

    it('should count active users as those with orders', () => {
      createUser('u1', 'Alice');
      createUser('u2', 'Bob');
      createUser('u3', 'Carol');
      createOrder('o1', 'u1', 10);

      const summary = service.getSummary();
      expect(summary.totalUsers).toBe(3);
      expect(summary.activeUsers).toBe(1);
    });
  });

  describe('getUserAnalytics', () => {
    it('should throw for non-existent user', () => {
      expect(() => service.getUserAnalytics('nonexistent')).toThrow('User not found');
    });

    it('should return analytics for user with no orders', () => {
      const user = createUser('u1', 'Alice');
      const analytics = service.getUserAnalytics('u1');

      expect(analytics.userId).toBe('u1');
      expect(analytics.orderCount).toBe(0);
      expect(analytics.totalSpent).toBe(0);
      expect(analytics.lastActive).toEqual(user.createdAt);
    });

    it('should calculate order count and total spent', () => {
      createUser('u1', 'Alice');
      createOrder('o1', 'u1', 100);
      createOrder('o2', 'u1', 50);

      const analytics = service.getUserAnalytics('u1');
      expect(analytics.orderCount).toBe(2);
      expect(analytics.totalSpent).toBe(150);
    });

    it('should exclude cancelled orders from total spent', () => {
      createUser('u1', 'Alice');
      createOrder('o1', 'u1', 100, 'confirmed');
      createOrder('o2', 'u1', 50, 'cancelled');

      const analytics = service.getUserAnalytics('u1');
      expect(analytics.orderCount).toBe(2);
      expect(analytics.totalSpent).toBe(100);
    });

    it('should use the most recent order updatedAt as lastActive', () => {
      createUser('u1', 'Alice');
      createOrder('o1', 'u1', 50, 'confirmed', yesterday);
      createOrder('o2', 'u1', 30, 'confirmed', now);

      const analytics = service.getUserAnalytics('u1');
      expect(analytics.lastActive).toEqual(now);
    });
  });

  describe('getTrends', () => {
    it('should return empty array when there are no orders', () => {
      const trends = service.getTrends();
      expect(trends).toEqual([]);
    });

    it('should group orders by date with order count and revenue', () => {
      createUser('u1', 'Alice');
      createOrder('o1', 'u1', 100, 'confirmed', new Date('2025-06-14T08:00:00Z'));
      createOrder('o2', 'u1', 50, 'confirmed', new Date('2025-06-14T16:00:00Z'));
      createOrder('o3', 'u1', 75, 'confirmed', new Date('2025-06-15T10:00:00Z'));

      const trends = service.getTrends();
      expect(trends).toHaveLength(4); // 2 dates * 2 metrics

      const june14Orders = trends.find(
        (t) => t.timestamp.toISOString().startsWith('2025-06-14') && t.metric === 'orders',
      );
      expect(june14Orders?.value).toBe(2);

      const june14Revenue = trends.find(
        (t) => t.timestamp.toISOString().startsWith('2025-06-14') && t.metric === 'revenue',
      );
      expect(june14Revenue?.value).toBe(150);

      const june15Orders = trends.find(
        (t) => t.timestamp.toISOString().startsWith('2025-06-15') && t.metric === 'orders',
      );
      expect(june15Orders?.value).toBe(1);
    });

    it('should exclude cancelled orders from revenue trends', () => {
      createUser('u1', 'Alice');
      createOrder('o1', 'u1', 100, 'confirmed', now);
      createOrder('o2', 'u1', 50, 'cancelled', now);

      const trends = service.getTrends();
      const revenueTrend = trends.find((t) => t.metric === 'revenue');
      expect(revenueTrend?.value).toBe(100);

      // Cancelled orders still count in order count
      const ordersTrend = trends.find((t) => t.metric === 'orders');
      expect(ordersTrend?.value).toBe(2);
    });

    it('should return trends sorted by date', () => {
      createUser('u1', 'Alice');
      createOrder('o1', 'u1', 50, 'confirmed', new Date('2025-06-16T10:00:00Z'));
      createOrder('o2', 'u1', 30, 'confirmed', new Date('2025-06-14T10:00:00Z'));

      const trends = service.getTrends();
      const timestamps = trends.map((t) => t.timestamp.getTime());
      // Each date produces 2 entries (orders, revenue), so check pairs
      expect(timestamps[0]).toBeLessThan(timestamps[2]!);
    });
  });
});

